Your task is to write a Jest test case that exposes a specific mutation in a JavaScript/TypeScript project.

MUTATION DETAILS
The mutation affects the following file:
sinks/drain.js
Here is the full content of that file (shown with a <PLACEHOLDER> marker):
'use strict'

module.exports = function drain (op, done) {
  var read, abort

  // Declared here so that it captures the drain's stack trace
  var doneLackingErr
  if (!done) {
    doneLackingErr = new Error('no done callback supplied')
  }

  function sink (_read) {
    read = _read
    if(abort) return sink.abort()
    //this function is much simpler to write if you
    //just use recursion, but by using a while loop
    //we do not blow the stack if the stream happens to be sync.
    ;(function next() {
           var loop = true, cbed = true

        while(loop) {
          cbed = false
          read(null, function (end, data) {
            cbed = true
            if(end = end || abort) {
              <PLACEHOLDER>
              if(done) done(end === true ? null : end)
              else if(end && end !== true) {
                console.warn(doneLackingErr)
                throw end
              }
            }
            else if(op && false === op(data) || abort) {
              loop = false
              read(abort || true, done || function () {})
            }
            else if(!loop){
              next()
            }
          })
          if(!cbed) {
            loop = false
            return
          }
        }
      })()
  }

  sink.abort = function (err, cb) {
    if('function' == typeof err)
      cb = err, err = true
    abort = err || true
    if(read) return read(abort, cb || function () {})
  }

  return sink
}

In the original code, <PLACEHOLDER> has the value:

-                 if(done) done(end === true ? null : end)
In the mutated code, <PLACEHOLDER> has the value:

+                 if(true) done(end === true ? null : end)


YOUR TASK
Write one Jest test file that:
    1. Passes when run against the original code.
    2. Fails when run against the mutated code.
    3. Tests the behavior of the mutated file in a way that reliably detects the mutation.
The test will be saved at the following path, relative to this test-generation project’s root:
llm-cache/anthropic_claude-sonnet-4.6/temp_0.5/withoutTests/cached/artifacts/pull-stream/attempt_1/pending_category/mutant-79747e0/testCase.test.ts

ALLOWED LIBRARIES
You may use:
    1. Any built-in Node.js modules (e.g., fs, path, crypto, etc.).

You may not use any other third-party libraries.

Looking at the mutation, the change is:
- Original: `if(done) done(end === true ? null : end)`
- Mutated: `if(true) done(end === true ? null : end)`

The difference is that in the mutated code, `done` is always called even when it's `undefined` (no `done` callback was supplied). This would cause a `TypeError: done is not a function` when `done` is not provided and the stream ends.

In the original code, when no `done` callback is supplied, it checks `if(done)` which is falsy for `undefined`, so it skips calling `done`. Instead it falls through to the `else if(end && end !== true)` branch which logs a warning and throws.

So I need a test where:
1. No `done` callback is provided
2. The stream ends normally (with `end === true`)

In the original code: `if(done)` is false, so it goes to `else if(end && end !== true)` - but since `end === true`, `end !== true` is false, so nothing happens (no throw, no warning).

In the mutated code: `if(true) done(...)` - `done` is `undefined`, so calling `undefined(...)` throws `TypeError`.

Let me write a test that creates a drain without a `done` callback and pipes a stream that ends normally. The original should complete without error, but the mutated code should throw.

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js"

describe('drain without done callback - normal stream end', () => {
  it('should not throw when stream ends normally and no done callback is provided', (done) => {
    // Create a simple source that emits one value then ends
    let count = 0
    const source = (end: any, cb: (end: any, data?: any) => void) => {
      if (end) return cb(end, null)
      if (count === 0) {
        count++
        cb(null, 'value1')
      } else {
        cb(true, null) // end of stream
      }
    }

    // The drain without a done callback - should complete without throwing
    // when stream ends normally (end === true)
    let threw = false
    try {
      const sink = drain(null)
      sink(source)
      // If we get here without throwing, the test should pass
      // Use setImmediate to allow async operations to complete
      setImmediate(() => {
        expect(threw).toBe(false)
        done()
      })
    } catch (e) {
      threw = true
      done(e)
    }
  })
})
```

Wait, the issue is that the source is synchronous here, so the throw would happen synchronously. Let me reconsider and make the test catch the error properly.

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js"

describe('drain without done callback', () => {
  it('should not throw when stream ends normally without a done callback', () => {
    let count = 0
    const source = (end: any, cb: (end: any, data?: any) => void) => {
      if (end) return cb(end, null)
      if (count === 0) {
        count++
        cb(null, 'value1')
      } else {
        cb(true, null)
      }
    }

    const sink = drain(null)

    expect(() => {
      sink(source)
    }).not.toThrow()
  })
})
```
